{ title: "Check-in im Hotel in Amman", scene: "Du kommst abends in einem Hotel in Amman an. Du gehst zur Rezeption und möchtest einchecken.", lines: [{ who: "them", ar: "مساء الخير، أهلا بك", de: "Guten Abend, willkommen." }, { who: "you", ar: "مساء الخير، عندي حجز", de: "Guten Abend, ich habe eine Reservierung." }, { who: "them", ar: "ما اسمك من فضلك؟", de: "Wie ist Ihr Name bitte?" }, { who: "you", ar: "اسمي توماس مولر", de: "Mein Name ist Thomas Müller." }, { who: "them", ar: "هل عندك جواز السفر؟", de: "Haben Sie den Reisepass?" }, { who: "you", ar: "نعم، هذا جواز سفري", de: "Ja, das ist mein Reisepass." }, { who: "them", ar: "أنت تبقى ليلتين، صحيح؟", de: "Sie bleiben zwei Nächte, richtig?" }, { who: "you", ar: "نعم، ليلتين", de: "Ja, zwei Nächte." }, { who: "them", ar: "الإفطار مشمول والواي فاي مجاني", de: "Frühstück ist inklusive und WLAN ist kostenlos." }, { who: "you", ar: "ما كلمة سر الواي فاي؟", de: "Wie lautet das WLAN-Passwort?" }, { who: "them", ar: "كلمة السر مكتوبة هنا", de: "Das Passwort steht hier." }, { who: "you", ar: "شكرا جزيلا على مساعدتك", de: "Vielen Dank für Ihre Hilfe." }] },
{ title: "Nach dem Weg in der Altstadt fragen", scene: "Du bist in einer engen Straße in Jerusalem und suchst den Markt. Du sprichst eine Person freundlich an.", lines: [{ who: "you", ar: "لو سمحت، أين السوق؟", de: "Entschuldigen Sie, wo ist der Markt?" }, { who: "them", ar: "السوق قريب من هنا", de: "Der Markt ist nah von hier." }, { who: "you", ar: "هل أذهب مستقيمًا؟", de: "Gehe ich geradeaus?" }, { who: "them", ar: "نعم، اذهب مستقيمًا ثم يمينًا", de: "Ja, gehen Sie geradeaus und dann rechts." }, { who: "you", ar: "بعد ذلك، أين السوق؟", de: "Danach, wo ist der Markt?" }, { who: "them", ar: "السوق بجانب المسجد الكبير", de: "Der Markt ist neben der großen Moschee." }, { who: "you", ar: "هل هو بعيد؟", de: "Ist er weit?" }, { who: "them", ar: "لا، خمس دقائق فقط", de: "Nein, nur fünf Minuten." }, { who: "you", ar: "شكرا على المساعدة", de: "Danke für die Hilfe." }, { who: "them", ar: "عفوا، رحلة سعيدة", de: "Gern, gute Reise." }, { who: "you", ar: "يومك سعيد", de: "Einen schönen Tag." }, { who: "them", ar: "يومك سعيد أيضا", de: "Ihnen auch einen schönen Tag." }] },
{ title: "Im Restaurant in Beirut", scene: "Du bist in einem Restaurant in Beirut und möchtest ein lokales Gericht probieren. Der Kellner erklärt dir kurz die Speisekarte.", lines: [{ who: "them", ar: "أهلا، هل عندك حجز؟", de: "Hallo, haben Sie eine Reservierung?" }, { who: "you", ar: "لا، أريد طاولة لشخص واحد", de: "Nein, ich möchte einen Tisch für eine Person." }, { who: "them", ar: "تفضل، هذه قائمة الطعام", de: "Bitte, hier ist die Speisekarte." }, { who: "you", ar: "ما الطبق المشهور هنا؟", de: "Was ist hier das bekannte Gericht?" }, { who: "them", ar: "الدجاج مع الأرز مشهور جدا", de: "Das Huhn mit Reis ist sehr bekannt." }, { who: "you", ar: "هل الطعام حار؟", de: "Ist das Essen scharf?" }, { who: "them", ar: "لا، ليس حارا جدا", de: "Nein, es ist nicht sehr scharf." }, { who: "you", ar: "أريد الدجاج مع الأرز وماء بدون غاز", de: "Ich möchte Huhn mit Reis und stilles Wasser." }, { who: "them", ar: "ممتاز، هل تريد مقبلات؟", de: "Ausgezeichnet, möchten Sie Vorspeisen?" }, { who: "you", ar: "نعم، سلطة صغيرة من فضلك", de: "Ja, einen kleinen Salat bitte." }, { who: "them", ar: "حاضر", de: "In Ordnung." }, { who: "you", ar: "شكرا جزيلا", de: "Vielen Dank." }] },
{ title: "Ein Zugticket in Marokko kaufen", scene: "Du bist am Bahnhof in Casablanca. Du möchtest mit dem Zug nach Marrakesch fahren und kaufst ein Ticket.", lines: [{ who: "them", ar: "صباح الخير، إلى أين؟", de: "Guten Morgen, wohin?" }, { who: "you", ar: "أريد تذكرة إلى مراكش من فضلك", de: "Ich möchte bitte ein Ticket nach Marrakesch." }, { who: "them", ar: "ذهاب فقط أم ذهاب وعودة؟", de: "Nur Hinfahrt oder Hin- und Rückfahrt?" }, { who: "you", ar: "ذهاب فقط", de: "Nur Hinfahrt." }, { who: "them", ar: "درجة أولى أم درجة ثانية؟", de: "Erste Klasse oder zweite Klasse?" }, { who: "you", ar: "درجة ثانية من فضلك", de: "Zweite Klasse bitte." }, { who: "them", ar: "هل تريد مقعدا بجانب النافذة؟", de: "Möchten Sie einen Fensterplatz?" }, { who: "you", ar: "نعم، بجانب النافذة", de: "Ja, am Fenster." }, { who: "them", ar: "القطار يغادر الساعة الثالثة", de: "Der Zug fährt um drei Uhr ab." }, { who: "you", ar: "هل يوجد تأخير؟", de: "Gibt es Verspätung?" }, { who: "them", ar: "لا، لا يوجد تأخير", de: "Nein, es gibt keine Verspätung." }, { who: "you", ar: "شكرا، هذا ممتاز", de: "Danke, das ist ausgezeichnet." }] },
{ title: "Auf dem Markt in Fès einkaufen", scene: "Du gehst über einen Markt in Fès und siehst eine schöne Tasche. Du möchtest nach dem Preis fragen und höflich verhandeln.", lines: [{ who: "them", ar: "أهلا، تفضل", de: "Hallo, bitte schön." }, { who: "you", ar: "مرحبا، كم سعر هذه الحقيبة؟", de: "Hallo, wie viel kostet diese Tasche?" }, { who: "them", ar: "السعر مئتا درهم", de: "Der Preis ist zweihundert Dirham." }, { who: "you", ar: "هذا غالي جدا", de: "Das ist sehr teuer." }, { who: "them", ar: "لكنها جميلة وتقليدية", de: "Aber sie ist schön und traditionell." }, { who: "you", ar: "هل ممكن سعر أقل؟", de: "Ist ein niedrigerer Preis möglich?" }, { who: "them", ar: "ممكن مئة وخمسون درهما", de: "Möglich sind einhundertfünfzig Dirham." }, { who: "you", ar: "هل عندك لون آخر؟", de: "Haben Sie eine andere Farbe?" }, { who: "them", ar: "نعم، عندي أسود وأبيض", de: "Ja, ich habe Schwarz und Weiß." }, { who: "you", ar: "أريد الحقيبة السوداء", de: "Ich möchte die schwarze Tasche." }, { who: "them", ar: "ممتاز، سآخذها لك", de: "Ausgezeichnet, ich nehme sie für Sie." }, { who: "you", ar: "شكرا، سآخذ هذا", de: "Danke, ich nehme das." }] },
{ title: "In der Apotheke in Amman", scene: "Du hast Kopfschmerzen und gehst in eine Apotheke. Du erklärst dein Problem und fragst nach einem Medikament.", lines: [{ who: "them", ar: "أهلا، كيف أساعدك؟", de: "Hallo, wie kann ich Ihnen helfen?" }, { who: "you", ar: "عندي صداع", de: "Ich habe Kopfschmerzen." }, { who: "them", ar: "هل عندك حمى؟", de: "Haben Sie Fieber?" }, { who: "you", ar: "لا، فقط صداع", de: "Nein, nur Kopfschmerzen." }, { who: "them", ar: "هل عندك حساسية من دواء؟", de: "Haben Sie eine Medikamentenallergie?" }, { who: "you", ar: "لا، ليس عندي حساسية", de: "Nein, ich habe keine Allergie." }, { who: "them", ar: "هذا دواء للصداع", de: "Das ist ein Medikament gegen Kopfschmerzen." }, { who: "you", ar: "كيف أستعمل هذا؟", de: "Wie benutze ich das?" }, { who: "them", ar: "قرص واحد مع الماء", de: "Eine Tablette mit Wasser." }, { who: "you", ar: "هل أحتاج إلى وصفة؟", de: "Brauche ich ein Rezept?" }, { who: "them", ar: "لا، لا تحتاج إلى وصفة", de: "Nein, Sie brauchen kein Rezept." }, { who: "you", ar: "شكرا على المساعدة", de: "Danke für die Hilfe." }] },
{ title: "Small Talk mit einem Einheimischen in Tunis", scene: "Du sitzt in Tunis auf einer Terrasse und kommst mit einer freundlichen Person ins Gespräch. Du sprichst langsam und benutzt einfache Sätze.", lines: [{ who: "you", ar: "مرحبا، هل هذا المكان فارغ؟", de: "Hallo, ist dieser Platz frei?" }, { who: "them", ar: "نعم، تفضل", de: "Ja, bitte." }, { who: "you", ar: "شكرا، أنا أتعلم العربية قليلا", de: "Danke, ich lerne ein bisschen Arabisch." }, { who: "them", ar: "ممتاز، من أين أنت؟", de: "Ausgezeichnet, woher kommen Sie?" }, { who: "you", ar: "أنا من ألمانيا", de: "Ich komme aus Deutschland." }, { who: "them", ar: "أهلا بك في تونس", de: "Willkommen in Tunesien." }, { who: "you", ar: "شكرا، المدينة جميلة جدا", de: "Danke, die Stadt ist sehr schön." }, { who: "them", ar: "هل هذه أول زيارة لك؟", de: "Ist das Ihr erster Besuch?" }, { who: "you", ar: "نعم، هذه أول زيارة لي", de: "Ja, das ist mein erster Besuch." }, { who: "them", ar: "هل تحب الطعام هنا؟", de: "Mögen Sie das Essen hier?" }, { who: "you", ar: "نعم، أحب الطعام والناس لطفاء جدا", de: "Ja, ich mag das Essen und die Leute sind sehr nett." }, { who: "them", ar: "رحلة سعيدة ومرحبا بك دائما", de: "Gute Reise, und Sie sind immer willkommen." }] }
